frappe.ui.form.on('User', {
  refresh(frm) {
    if (frm.is_new()) return;
    if (!(frappe.session.user === 'Administrator' || frappe.user.has_role('System Manager'))) return;
    if (frm.doc.name === 'Administrator') return;
    if (!frm.doc.enabled) return;

    frm.add_custom_button(__('Login as User'), () => {
      frappe.confirm(
        __('Log in as {0}? This will end your current admin session.', [frm.doc.name]),
        () => {
          frappe.call({
            method: 'frappe.custom_impersonate.login_as',
            args: { target_user: frm.doc.name },
            freeze: true,
            freeze_message: __('Signing in as {0}', [frm.doc.name]),
            callback: function(r) {
              if (!r.exc) {
                window.location.href = '/app';
              }
            }
          });
        }
      );
    }, __('Admin'));
  }
});
